// Detect which trigger fired this execution
// $('NodeName').first() throws if the node wasn't executed in this run
let trigger = 'manual';
let syncParams = {};
try { $('Heartbeat (15m)').first(); trigger = 'heartbeat'; } catch(e) {}
try { $('Executions (3h)').first(); trigger = 'executions'; } catch(e) {}
try { $('Config (3h)').first(); trigger = 'configuration'; } catch(e) {}
try { $('Error Trigger').first(); trigger = 'error'; } catch(e) {}
try {
  const wh = $('Manual Webhook').first();
  trigger = 'manual';
  syncParams.timeframe = wh.json.body?.timeframe || '1h';
  syncParams.level = wh.json.body?.level || 'simple';
} catch(e) {}

return [{ json: { telemetry_type: trigger, syncParams } }];

// Process Executions: Merge execution metadata + token data from Extract Tokens loop
// Execution list comes from $('Get Executions') n8n node, token data from $input (Aggregate)

// 1. Get execution metadata (n8n node returns items directly, no data wrapper)
let executions = [];
try {
  executions = $('Get Executions').all().map(i => i.json);
} catch (e) {
  executions = [];
}

// 2. Get token data from the Extract Tokens → Aggregate path
let tokenRows = [];
try {
  const rawItems = $input.all().map(i => i.json);
  if (rawItems.length === 1 && Array.isArray(rawItems[0].data)) {
    tokenRows = rawItems[0].data;
  } else if (rawItems.length > 0 && rawItems[0].execution_id) {
    tokenRows = rawItems;
  } else {
    tokenRows = rawItems.flatMap(r => r.data || [r]);
  }
} catch (e) {
  tokenRows = [];
}

// 3. Group token rows by execution_id
const tokensByExec = {};
for (const row of tokenRows) {
  const execId = String(row.execution_id);
  if (!tokensByExec[execId]) tokensByExec[execId] = [];
  if ((row.tokens_input || 0) > 0 || (row.tokens_output || 0) > 0) {
    tokensByExec[execId].push({
      model: row.model || 'unknown',
      tokens_input: parseInt(row.tokens_input) || 0,
      tokens_output: parseInt(row.tokens_output) || 0,
      node_name: row.node_name || undefined,
    });
  }
}

// 4. Merge: attach token_usage to each execution, pass through error fields
const processed = executions.map(exec => {
  const execId = String(exec.id);
  const errorMsg = exec.error?.message || exec.error?.description || null;

  return {
    json: {
      id: exec.id,
      workflowId: exec.workflowId,
      status: exec.status,
      finished: exec.finished,
      mode: exec.mode,
      startedAt: exec.startedAt,
      stoppedAt: exec.stoppedAt,
      lastNodeExecuted: exec.lastNodeExecuted || null,
      error_message: errorMsg,
      token_usage: tokensByExec[execId] || [],
    }
  };
});

return processed;

const trigger = $('Route Telemetry').first().json.telemetry_type;

const SENTINEL_URL = 'YOUR_SENTINEL_URL';
const INSTANCE_ID = 'YOUR_INSTANCE_ID';
const nonce = Date.now().toString(36) + '-' + Math.random().toString(36).slice(2);

// Helper: unwrap n8n API responses which return { data: [...] }
// Handles both single-page and paginated (multi-page) responses
function unwrapApiResponse(items) {
  const raw = items.map(i => i.json);
  if (raw.length === 1 && raw[0].data && Array.isArray(raw[0].data)) {
    return raw[0].data;
  }
  if (raw.length > 1 && raw[0].data && Array.isArray(raw[0].data)) {
    return raw.flatMap(r => r.data || []);
  }
  return raw;
}

// Read real n8n settings (populated on heartbeat path via Get n8n Settings node)
let n8nSettings = {};
try {
  const raw = $('Get n8n Settings').first().json;
  n8nSettings = raw.data || raw || {};
} catch(e) {}

// Detect database type via Postgres probe (continueOnFail node)
let dbType = null;
try {
  const dbProbe = $('Detect DB Type').first().json;
  if (dbProbe && dbProbe.database_type) dbType = dbProbe.database_type;
} catch(e) {}

const payload = {
  schema_version: '1.0.0',
  instance_id: INSTANCE_ID,
  timestamp: new Date().toISOString(),
  nonce: nonce,
  reporter_version: '1.4.0',
  telemetry_type: trigger,
  instance_metadata: {
    n8n_version: n8nSettings.versionCli || null,
    database_type: dbType,
    instance_url: (() => {
      try {
        const cb = n8nSettings.oauthCallbackUrls?.oauth2;
        if (cb) { const u = new URL(cb); return u.origin; }
      } catch(e) {}
      return null;
    })(),
    timezone: n8nSettings.timezone || Intl.DateTimeFormat().resolvedOptions().timeZone
  },
  data: {}
};

if (trigger === 'configuration') {
  try {
    const wfItems = unwrapApiResponse($('Get Workflows').all());
    payload.data.workflows = wfItems;
  } catch (e) {
    payload.data.workflows = [];
  }
} else if (trigger === 'executions' || trigger === 'manual') {
  try {
    const execItems = $('Process Executions').all().map(i => i.json);
    payload.data.executions = execItems;
  } catch (e) {
    payload.data.executions = [];
  }
} else if (trigger === 'error') {
  try {
    const raw = $('Error Trigger').first().json;
    const exec = raw.execution || {};
    const wf = raw.workflow || {};
    const errObj = exec.error || {};
    payload.data.error = {
      id: exec.id,
      workflowId: wf.id,
      workflowName: wf.name,
      status: 'error',
      startedAt: exec.startedAt || exec.started_at,
      stoppedAt: exec.stoppedAt || exec.stopped_at,
      mode: exec.mode,
      error_message: errObj.message || errObj.description || raw.message || 'Unknown error',
      error_node: exec.lastNodeExecuted || null,
    };
  } catch (e) {
    payload.data.error = { status: 'error', error_message: 'Error data unavailable' };
  }
}

return [{
  json: {
    url: SENTINEL_URL,
    payload: payload,
    payloadString: JSON.stringify(payload)
  }
}];

const INPUT_KEYS = [
  'prompt_tokens', 'input_tokens', 'promptTokens', 'promptTokenCount',
  'input_token_count', 'inputTokens'
];
const OUTPUT_KEYS = [
  'completion_tokens', 'output_tokens', 'completionTokens', 'candidatesTokenCount',
  'output_token_count', 'outputTokens'
];
const MODEL_KEYS = ['model_name', 'model', 'modelId', 'model_id', 'modelName'];

const NODE_TYPE_TO_PROVIDER = {
  'lmChatAnthropic': 'anthropic',
  'lmChatOpenAi': 'openai',
  'lmChatAzureOpenAi': 'azure_openai',
  'lmChatAwsBedrock': 'aws_bedrock',
  'lmChatCohere': 'cohere',
  'lmChatDeepSeek': 'deepseek',
  'lmChatGoogleGemini': 'google',
  'lmChatGoogleVertex': 'google_vertex',
  'lmChatGroq': 'groq',
  'lmChatMistralCloud': 'mistral',
  'lmChatOpenRouter': 'openrouter',
  'lmChatVercelAiGateway': 'vercel_gateway',
  'lmChatXAiGrok': 'xai',
  'lmChatLemonade': 'lemonade',
  'lmChatOllama': 'ollama',
  'lmChatAlibabaCloud': 'alibaba',
  'lmOpenAi': 'openai',
  'lmCohere': 'cohere',
  'lmOllama': 'ollama',
  'lmLemonade': 'lemonade',
  'lmOpenHuggingFaceInference': 'huggingface',
  'openAi': 'openai',
  'anthropic': 'anthropic',
  'googleGemini': 'google',
  'ollama': 'ollama',
  'openAiAssistant': 'openai',
  'mistralAi': 'mistral',
};

function providerFallback(shortType) {
  let cleaned = shortType.replace(/^(lmChat|lm|embeddingsChat|embeddings)/i, '');
  if (!cleaned || cleaned === shortType) return null;
  return cleaned.charAt(0).toLowerCase() + cleaned.slice(1);
}

function providerFromModel(modelName) {
  if (!modelName) return null;
  const m = modelName.toLowerCase();
  if (m.startsWith('gpt-') || m.startsWith('o1') || m.startsWith('o3') || m.startsWith('o4')) return 'openai';
  if (m.startsWith('claude-')) return 'anthropic';
  if (m.startsWith('gemini')) return 'google';
  if (m.includes('llama') || m.includes('groq')) return 'groq';
  if (m.startsWith('mistral') || m.startsWith('mixtral')) return 'mistral';
  if (m.includes('deepseek')) return 'deepseek';
  if (m.includes('command')) return 'cohere';
  if (m.includes('qwen')) return 'alibaba';
  return null;
}

function getProviderFromNodeType(nodeType) {
  const shortType = (nodeType || '').split('.').pop() || '';
  return NODE_TYPE_TO_PROVIDER[shortType] || providerFallback(shortType) || null;
}

function buildNodeMap(workflowData) {
  const map = {};
  if (!workflowData?.nodes) return map;
  for (const node of workflowData.nodes) {
    const provider = getProviderFromNodeType(node.type);
    if (provider) {
      map[node.name] = { provider, type: node.type };
    }
  }
  return map;
}

function findModelTargeted(nodeData) {
  let model = null;
  const walk = (obj, depth) => {
    if (depth > 30 || !obj || typeof obj !== 'object' || model) return;
    if (!Array.isArray(obj)) {
      if (obj.generationInfo) {
        for (const key of MODEL_KEYS) {
          if (obj.generationInfo[key] && typeof obj.generationInfo[key] === 'string'
              && !/^\d+$/.test(obj.generationInfo[key])) {
            model = obj.generationInfo[key];
            return;
          }
        }
      }
      if (obj.tokenUsage || obj.token_usage || obj.usage) {
        for (const key of MODEL_KEYS) {
          if (obj[key] && typeof obj[key] === 'string' && !/^\d+$/.test(obj[key])) {
            model = obj[key];
            return;
          }
        }
      }
      if (obj.type === 'message' || obj.stop_reason) {
        for (const key of MODEL_KEYS) {
          if (obj[key] && typeof obj[key] === 'string' && !/^\d+$/.test(obj[key])) {
            model = obj[key];
            return;
          }
        }
      }
    }
    const entries = Array.isArray(obj) ? obj : Object.values(obj);
    for (const val of entries) {
      if (val && typeof val === 'object') walk(val, depth + 1);
      if (model) return;
    }
  };
  walk(nodeData, 0);
  return model;
}

function findUsageObjects(obj, results = [], depth = 0) {
  if (depth > 50 || obj === null || typeof obj !== 'object') return results;
  if (!Array.isArray(obj)) {
    const keys = Object.keys(obj);
    const inputKey = INPUT_KEYS.find(k => keys.includes(k));
    const outputKey = OUTPUT_KEYS.find(k => keys.includes(k));
    if (inputKey || outputKey) {
      results.push({
        tokens_input: Number(obj[inputKey]) || 0,
        tokens_output: Number(obj[outputKey]) || 0,
      });
    }
  }
  const entries = Array.isArray(obj) ? obj : Object.values(obj);
  for (const val of entries) {
    if (val && typeof val === 'object') findUsageObjects(val, results, depth + 1);
  }
  return results;
}

function dedupeUsage(usages) {
  const seen = new Set();
  return usages.filter(u => {
    const key = `${u.tokens_input}:${u.tokens_output}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

const items = $input.all();
const results = [];

for (const item of items) {
  const exec = item.json;
  const execId = exec.id;
  const workflowId = exec.workflowId;
  const runData = exec.data?.resultData?.runData || {};
  const nodeMap = buildNodeMap(exec.workflowData);

  let allUsages = [];
  let model = 'unknown';
  let provider = 'unknown';

  for (const [nodeName, runs] of Object.entries(runData)) {
    const usages = findUsageObjects(runs);
    if (usages.length > 0) {
      allUsages.push(...usages);
      if (model === 'unknown') {
        model = findModelTargeted(runs) || 'unknown';
      }
      if (provider === 'unknown' && nodeMap[nodeName]) {
        provider = nodeMap[nodeName].provider;
      }
    }
  }

  if (provider === 'unknown') {
    for (const [name, info] of Object.entries(nodeMap)) {
      if (info.type && (info.type.includes('lmChat') || info.type.includes('lm'))) {
        provider = info.provider;
        break;
      }
    }
  }

  if (provider === 'unknown' && model !== 'unknown') {
    provider = providerFromModel(model) || 'unknown';
  }

  allUsages = dedupeUsage(allUsages);

  results.push({
    json: {
      execution_id: execId,
      workflow_id: workflowId,
      model: allUsages.length > 0 ? model : null,
      provider: allUsages.length > 0 ? provider : null,
      tokens_input: allUsages.reduce((sum, u) => sum + u.tokens_input, 0),
      tokens_output: allUsages.reduce((sum, u) => sum + u.tokens_output, 0),
      usage_count: allUsages.length,
    }
  });
}

return results;
